module RefModule(
  input touch_in,
  output led_out
);reg touch_state = 0;

  always @(touch_in) begin
    if (touch_in == 1) begin
      touch_state <= 1;
    end else begin
      touch_state <= 0;
    end
  end

  wire __led_out_tmp = touch_state;
  assign led_out = __led_out_tmp;

endmodule
